import{_ as t,o as i,c as n,ai as a}from"./chunks/framework.B3x_xFnx.js";const c=JSON.parse('{"title":"Maintainer Requirements","description":"","frontmatter":{},"headers":[],"relativePath":"JoinTheTeam/MaintainersRequirements.md","filePath":"JoinTheTeam/MaintainersRequirements.md"}'),o={name:"JoinTheTeam/MaintainersRequirements.md"};function r(s,e,l,d,p,u){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="maintainer-requirements" tabindex="-1">Maintainer Requirements <a class="header-anchor" href="#maintainer-requirements" aria-label="Permalink to “Maintainer Requirements”">​</a></h1><p>Before you apply to add your device into our list of official devices, there are certain requirements that you are expected to fulfill in order to be considered. Some of them are outlined below:</p><p><strong>Any failure in complying with the following will make you unfit for the maintainership. No questions asked.</strong></p><p>1.1. You <strong>MUST</strong> own the device you plan to maintain for. Blind and untested builds aren&#39;t allowed. Devices that have minimal hardware difference from yours are allowed to be maintained, as long as you maintain your own device too.</p><p>1.2. You <strong>SHOULD</strong> have a strong knowledge of Git and version control.</p><p>1.3. You <strong>MUST</strong> have experience maintaining the ROM on an unofficial basis for some amount of time. you <strong>MUST NOT</strong> instantly make a build and apply, that&#39;ll mean an instant rejection. This shows that you are capable of handling the responsibilities of a maintainer, and that you are committed to the project.</p><p>1.4. You <strong>MUST</strong> ensure that the ROM is stable for daily usage before applying. This is essential for providing a good user experience and ensuring that the build is widely usable. The context of stability may differ for different devices, so explain regarding any exceptions.</p><p>1.5. You <strong>MUST</strong> make the device sources for the ROM publicly available. This allows team members to verify the provided sources.</p><p>1.6. <strong>MUST NOT</strong> include any stolen or &quot;kanged&quot; commits without crediting the original author. This is unethical and can harm the ROM&#39;s reputation.</p><p>1.7. You <strong>MUST</strong> show the actual device sources being used. Any means to decieve us will lead to instant rejection</p><p>1.8. You <strong>MUST NOT</strong> lie on the maintainer application, this leads to instant rejection.</p><p>1.9. You <strong>SHOULD</strong> have made significant contributions to the device sources. This shows that you are actively involved in Android development and that you are committed to the project.</p><p>1.10. You <strong>SHOULD NOT</strong> be maintaining too many ROMs. This can spread your time and efforts too thin, and can lead to subpar maintenance of the ROMs you are responsible for.</p><p><strong>Other qualitative aspects that will be considered when reviewing your application, such as:</strong></p><p>2.1. Your previous/current work in development</p><p>2.2. Your behavior towards users</p><p>2.3. Your behavior towards the team members</p><p>2.4. Your activeness in the community</p><p><strong>Additionally</strong></p><p>3.1 PixelOS Team reserves the right to reject any application at its sole discretion, even in the absence of a valid reason.</p><p>3.2. PixelOS Team reserves the right to terminate any maintainer at any given time, irrespective of a valid reason or justification.</p><p>3.3. After being rejected or deemed invalid, you must wait a minimum of 90 days before submitting a new application.</p>',22)])])}const h=t(o,[["render",r]]);export{c as __pageData,h as default};
